/**
 * Analytics data model definitions.
 *
 * These types represent aggregated analytics data derived from
 * orders and users. Used by the AnalyticsService to produce
 * dashboard summaries, time-series data, and metric breakdowns.
 */

import type { OrderStatus } from './order.js';

/**
 * A single data point in a time series.
 */
export interface TimeSeriesDataPoint {
  /** ISO date string for the bucket (e.g., "2026-04-01") */
  date: string;
  /** Aggregated value for this time bucket */
  value: number;
}

/**
 * Time-series aggregation result.
 */
export interface TimeSeriesResult {
  /** Label describing what is measured (e.g., "orders", "revenue") */
  metric: string;
  /** The granularity of each bucket */
  granularity: TimeGranularity;
  /** Start of the time range (ISO string) */
  startDate: string;
  /** End of the time range (ISO string) */
  endDate: string;
  /** The data points */
  data: TimeSeriesDataPoint[];
}

/**
 * Supported time granularities for aggregation.
 */
export type TimeGranularity = 'day' | 'week' | 'month';

/**
 * Summary metrics for orders.
 */
export interface OrderMetricSummary {
  /** Total number of orders */
  totalOrders: number;
  /** Total revenue across all orders */
  totalRevenue: number;
  /** Average order value */
  averageOrderValue: number;
  /** Breakdown of orders by status */
  ordersByStatus: Record<OrderStatus, number>;
  /** Average number of items per order */
  averageItemsPerOrder: number;
}

/**
 * Summary metrics for users.
 */
export interface UserMetricSummary {
  /** Total number of users */
  totalUsers: number;
  /** Breakdown of users by role */
  usersByRole: Record<string, number>;
}

/**
 * Composed dashboard data combining multiple metric sources.
 */
export interface DashboardData {
  /** When this dashboard data was generated */
  generatedAt: Date;
  /** Order-related metrics */
  orderMetrics: OrderMetricSummary;
  /** User-related metrics */
  userMetrics: UserMetricSummary;
  /** Revenue over time */
  revenueTimeSeries: TimeSeriesResult;
  /** Order count over time */
  ordersTimeSeries: TimeSeriesResult;
  /** Top products by quantity sold */
  topProducts: ProductSummary[];
}

/**
 * Summary of a product's sales performance.
 */
export interface ProductSummary {
  productId: string;
  name: string;
  totalQuantity: number;
  totalRevenue: number;
}

/**
 * Options for querying time-series data.
 */
export interface TimeSeriesQuery {
  /** Start of the date range */
  startDate: Date;
  /** End of the date range */
  endDate: Date;
  /** Granularity of the time buckets */
  granularity: TimeGranularity;
}

/**
 * Analytics aggregation service — processes raw order and user data
 * into analytics summaries for the dashboard.
 *
 * Depends on:
 * - OrderRepository (data layer) for reading order data
 * - UserRepository (data layer) for reading user data
 *
 * Architecture note: This service is read-only — it queries repositories
 * to compute aggregated views. It does not modify any data.
 */

import type { Order } from '../models/order.js';
import type { OrderStatus } from '../models/order.js';
import type {
  TimeSeriesDataPoint,
  TimeSeriesResult,
  TimeSeriesQuery,
  TimeGranularity,
  OrderMetricSummary,
  UserMetricSummary,
  DashboardData,
  ProductSummary,
} from '../models/analytics.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

const ALL_ORDER_STATUSES: OrderStatus[] = [
  'pending',
  'confirmed',
  'shipped',
  'delivered',
  'cancelled',
];

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Generate a complete dashboard data snapshot.
   */
  getDashboardData(query: TimeSeriesQuery): DashboardData {
    this.logger.info('Generating dashboard data');

    const orderMetrics = this.getOrderMetricSummary();
    const userMetrics = this.getUserMetricSummary();
    const revenueTimeSeries = this.getRevenueTimeSeries(query);
    const ordersTimeSeries = this.getOrderCountTimeSeries(query);
    const topProducts = this.getTopProducts(10);

    return {
      generatedAt: new Date(),
      orderMetrics,
      userMetrics,
      revenueTimeSeries,
      ordersTimeSeries,
      topProducts,
    };
  }

  /**
   * Compute summary metrics for all orders.
   */
  getOrderMetricSummary(): OrderMetricSummary {
    this.logger.info('Computing order metric summary');

    const orders = this.orderRepository.findAll();

    const totalOrders = orders.length;
    const totalRevenue = orders.reduce((sum, order) => sum + order.total, 0);
    const averageOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0;

    const ordersByStatus = {} as Record<OrderStatus, number>;
    for (const status of ALL_ORDER_STATUSES) {
      ordersByStatus[status] = 0;
    }
    for (const order of orders) {
      ordersByStatus[order.status]++;
    }

    const totalItems = orders.reduce(
      (sum, order) =>
        sum + order.items.reduce((itemSum, item) => itemSum + item.quantity, 0),
      0,
    );
    const averageItemsPerOrder = totalOrders > 0 ? totalItems / totalOrders : 0;

    return {
      totalOrders,
      totalRevenue,
      averageOrderValue,
      ordersByStatus,
      averageItemsPerOrder,
    };
  }

  /**
   * Compute summary metrics for all users.
   */
  getUserMetricSummary(): UserMetricSummary {
    this.logger.info('Computing user metric summary');

    const users = this.userRepository.findAll();

    const usersByRole: Record<string, number> = {};
    for (const user of users) {
      usersByRole[user.role] = (usersByRole[user.role] ?? 0) + 1;
    }

    return {
      totalUsers: users.length,
      usersByRole,
    };
  }

  /**
   * Aggregate revenue into a time series.
   */
  getRevenueTimeSeries(query: TimeSeriesQuery): TimeSeriesResult {
    this.logger.info(
      `Computing revenue time series (${query.granularity}) from ${query.startDate.toISOString()} to ${query.endDate.toISOString()}`,
    );

    const orders = this.orderRepository.findAll();
    const buckets = this.buildTimeBuckets(query);

    for (const order of orders) {
      const bucketKey = this.dateToBucketKey(order.createdAt, query.granularity);
      const bucket = buckets.get(bucketKey);
      if (bucket !== undefined) {
        buckets.set(bucketKey, bucket + order.total);
      }
    }

    return {
      metric: 'revenue',
      granularity: query.granularity,
      startDate: query.startDate.toISOString(),
      endDate: query.endDate.toISOString(),
      data: this.bucketsToDataPoints(buckets),
    };
  }

  /**
   * Aggregate order counts into a time series.
   */
  getOrderCountTimeSeries(query: TimeSeriesQuery): TimeSeriesResult {
    this.logger.info(
      `Computing order count time series (${query.granularity}) from ${query.startDate.toISOString()} to ${query.endDate.toISOString()}`,
    );

    const orders = this.orderRepository.findAll();
    const buckets = this.buildTimeBuckets(query);

    for (const order of orders) {
      const bucketKey = this.dateToBucketKey(order.createdAt, query.granularity);
      const bucket = buckets.get(bucketKey);
      if (bucket !== undefined) {
        buckets.set(bucketKey, bucket + 1);
      }
    }

    return {
      metric: 'orders',
      granularity: query.granularity,
      startDate: query.startDate.toISOString(),
      endDate: query.endDate.toISOString(),
      data: this.bucketsToDataPoints(buckets),
    };
  }

  /**
   * Get top products ranked by total quantity sold.
   */
  getTopProducts(limit: number): ProductSummary[] {
    this.logger.info(`Computing top ${limit} products`);

    const orders = this.orderRepository.findAll();
    const productMap = new Map<
      string,
      { productId: string; name: string; totalQuantity: number; totalRevenue: number }
    >();

    for (const order of orders) {
      for (const item of order.items) {
        const existing = productMap.get(item.productId);
        if (existing) {
          existing.totalQuantity += item.quantity;
          existing.totalRevenue += item.quantity * item.unitPrice;
        } else {
          productMap.set(item.productId, {
            productId: item.productId,
            name: item.name,
            totalQuantity: item.quantity,
            totalRevenue: item.quantity * item.unitPrice,
          });
        }
      }
    }

    return Array.from(productMap.values())
      .sort((a, b) => b.totalQuantity - a.totalQuantity)
      .slice(0, limit);
  }

  /**
   * Get revenue breakdown by order status.
   */
  getRevenueByStatus(): Record<OrderStatus, number> {
    this.logger.info('Computing revenue by status');

    const orders = this.orderRepository.findAll();
    const result = {} as Record<OrderStatus, number>;
    for (const status of ALL_ORDER_STATUSES) {
      result[status] = 0;
    }
    for (const order of orders) {
      result[order.status] += order.total;
    }
    return result;
  }

  /**
   * Get orders for a specific user with summary stats.
   */
  getUserOrderSummary(userId: string): {
    totalOrders: number;
    totalSpent: number;
    averageOrderValue: number;
    ordersByStatus: Record<OrderStatus, number>;
  } {
    this.logger.info(`Computing order summary for user: ${userId}`);

    const orders = this.orderRepository.findByUserId(userId);
    const totalOrders = orders.length;
    const totalSpent = orders.reduce((sum, order) => sum + order.total, 0);

    const ordersByStatus = {} as Record<OrderStatus, number>;
    for (const status of ALL_ORDER_STATUSES) {
      ordersByStatus[status] = 0;
    }
    for (const order of orders) {
      ordersByStatus[order.status]++;
    }

    return {
      totalOrders,
      totalSpent,
      averageOrderValue: totalOrders > 0 ? totalSpent / totalOrders : 0,
      ordersByStatus,
    };
  }

  /**
   * Build empty time buckets for the given query range.
   */
  private buildTimeBuckets(query: TimeSeriesQuery): Map<string, number> {
    const buckets = new Map<string, number>();
    const current = new Date(query.startDate);
    const end = new Date(query.endDate);

    while (current <= end) {
      const key = this.dateToBucketKey(current, query.granularity);
      if (!buckets.has(key)) {
        buckets.set(key, 0);
      }
      this.advanceDate(current, query.granularity);
    }

    return buckets;
  }

  /**
   * Convert a Date to a bucket key string based on granularity.
   */
  private dateToBucketKey(date: Date, granularity: TimeGranularity): string {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');

    switch (granularity) {
      case 'day':
        return `${year}-${month}-${day}`;
      case 'week':
        return this.getWeekKey(date);
      case 'month':
        return `${year}-${month}`;
    }
  }

  /**
   * Get the ISO week-based key for a date (Monday-start week).
   */
  private getWeekKey(date: Date): string {
    // Find the Monday of this week
    const d = new Date(date);
    const dayOfWeek = d.getDay();
    const diff = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
    d.setDate(d.getDate() + diff);

    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${year}-W${month}-${day}`;
  }

  /**
   * Advance a date by one unit of the given granularity.
   */
  private advanceDate(date: Date, granularity: TimeGranularity): void {
    switch (granularity) {
      case 'day':
        date.setDate(date.getDate() + 1);
        break;
      case 'week':
        date.setDate(date.getDate() + 7);
        break;
      case 'month':
        date.setMonth(date.getMonth() + 1);
        break;
    }
  }

  /**
   * Convert a bucket map to sorted data points.
   */
  private bucketsToDataPoints(
    buckets: Map<string, number>,
  ): TimeSeriesDataPoint[] {
    return Array.from(buckets.entries())
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([date, value]) => ({ date, value }));
  }
}

