+    }
+    for (const order of orders) {
+      ordersByStatus[order.status]++;
+    }
+
+    return {
+      totalOrders,
+      totalSpent,
+      averageOrderValue: totalOrders > 0 ? totalSpent / totalOrders : 0,
+      ordersByStatus,
+    };
+  }
+
+  /**
+   * Build empty time buckets for the given query range.
+   */
+  private buildTimeBuckets(query: TimeSeriesQuery): Map<string, number> {
+    const buckets = new Map<string, number>();
+    const current = new Date(query.startDate);
+    const end = new Date(query.endDate);
+
+    while (current <= end) {
+      const key = this.dateToBucketKey(current, query.granularity);
+      if (!buckets.has(key)) {
+        buckets.set(key, 0);
+      }
+      this.advanceDate(current, query.granularity);
+    }
+
+    return buckets;
+  }
+
+  /**
+   * Convert a Date to a bucket key string based on granularity.
+   */
+  private dateToBucketKey(date: Date, granularity: TimeGranularity): string {
+    const year = date.getFullYear();
+    const month = String(date.getMonth() + 1).padStart(2, '0');
+    const day = String(date.getDate()).padStart(2, '0');
+
+    switch (granularity) {
+      case 'day':
+        return `${year}-${month}-${day}`;
+      case 'week':
+        return this.getWeekKey(date);
+      case 'month':
+        return `${year}-${month}`;
+    }
+  }
+
+  /**
+   * Get the ISO week-based key for a date (Monday-start week).
+   */
+  private getWeekKey(date: Date): string {
+    // Find the Monday of this week
+    const d = new Date(date);
+    const dayOfWeek = d.getDay();
+    const diff = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
+    d.setDate(d.getDate() + diff);
+
+    const year = d.getFullYear();
+    const month = String(d.getMonth() + 1).padStart(2, '0');
+    const day = String(d.getDate()).padStart(2, '0');
+    return `${year}-W${month}-${day}`;
+  }
+
+  /**
+   * Advance a date by one unit of the given granularity.
+   */
+  private advanceDate(date: Date, granularity: TimeGranularity): void {
+    switch (granularity) {
+      case 'day':
+        date.setDate(date.getDate() + 1);
+        break;
+      case 'week':
+        date.setDate(date.getDate() + 7);
+        break;
+      case 'month':
+        date.setMonth(date.getMonth() + 1);
+        break;
+    }
+  }
+
+  /**
+   * Convert a bucket map to sorted data points.
+   */
+  private bucketsToDataPoints(
+    buckets: Map<string, number>,
+  ): TimeSeriesDataPoint[] {
+    return Array.from(buckets.entries())
+      .sort(([a], [b]) => a.localeCompare(b))
+      .map(([date, value]) => ({ date, value }));
+  }
+}
